import streamlit as st
import os
import time
import json
import pandas as pd
from atproto import Client, models
import google.generativeai as genai
from google.generativeai.types import GenerationConfig
from dotenv import load_dotenv, set_key

# --- Initialization ---
load_dotenv(override=True)
AI_MODEL_NAME = os.getenv("GEMINI_API_MODEL", "gemini-1.5-flash")
DB_FILE = "managed_data.json"

st.set_page_config(page_title="AI SNS Strategic Agent Ultimate", layout="wide", page_icon="🔥")

# CSS for better layout
st.markdown("""
    <style>
    .main { padding-top: 1rem; }
    .stAlert { margin-top: 10px; margin-bottom: 10px; }
    .warning-text { color: #ff4b4b; font-weight: bold; font-size: 0.9rem; }
    .log-container {
        background-color: #0e1117;
        color: #00ff00;
        padding: 15px;
        border-radius: 5px;
        border: 1px solid #333;
        font-family: 'Courier New', Courier, monospace;
        margin: 10px 0;
        line-height: 1.4;
        max-height: 400px;
        overflow-y: auto;
    }
    </style>
""", unsafe_allow_html=True)

# --- Persistence ---
def load_db():
    if os.path.exists(DB_FILE):
        try:
            with open(DB_FILE, "r", encoding="utf-8") as f: return json.load(f)
        except: return {"removed": {}}
    return {"removed": {}}

def save_removed_user(did, handle, category, bio):
    db = load_db()
    db["removed"][did] = {"handle": handle, "category": category, "bio": bio, "time": time.time()}
    with open(DB_FILE, "w", encoding="utf-8") as f:
        json.dump(db, f, ensure_ascii=False, indent=2)

# --- Bluesky Helpers ---
def get_all_followers(client, did, max_count=500):
    followers = []
    cursor = None
    try:
        while len(followers) < max_count:
            res = client.get_followers(did, limit=min(100, max_count - len(followers)), cursor=cursor)
            followers.extend(res.followers)
            cursor = res.cursor
            if not cursor: break
            time.sleep(0.5)
    except Exception as e:
        st.error(f"Followers Error: {e}")
    return followers

def get_all_follows(client, did, max_count=500):
    follows = []
    cursor = None
    try:
        while len(follows) < max_count:
            res = client.get_follows(did, limit=min(100, max_count - len(follows)), cursor=cursor)
            follows.extend(res.follows)
            cursor = res.cursor
            if not cursor: break
            time.sleep(0.5)
    except Exception as e:
        st.error(f"Follows Error: {e}")
    return follows

# --- UI Header ---
st.title("🔥 AI SNS Strategic Agent")
st.caption(f"Strategy Automation | Model: {AI_MODEL_NAME}")

# --- Sidebar ---
with st.sidebar:
    st.header("🔌 Connection")
    bs_handle = st.text_input("Handle", value=os.getenv("BLUESKY_HANDLE", ""))
    bs_pwd = st.text_input("Password", type="password", value=os.getenv("BLUESKY_PASSWORD", ""))
    gemini_key = st.text_input("Gemini API Key", type="password", value=os.getenv("GEMINI_API_KEY", ""))

    if st.button("Save Config"):
        set_key(".env", "BLUESKY_HANDLE", bs_handle)
        set_key(".env", "BLUESKY_PASSWORD", bs_pwd)
        set_key(".env", "GEMINI_API_KEY", gemini_key)
        st.success("Updated! Please refresh or rerun.")

    st.divider()
    st.header("🎯 Strategy")
    kw_input = st.text_area("Target Keywords (Comma sep)", value="エンジニア, AI, Python")
    target_kws = [k.strip() for k in kw_input.split(",") if k.strip()]

# AI/Client Init
client = None
ai = None
if gemini_key and bs_handle and bs_pwd:
    try:
        genai.configure(api_key=gemini_key)
        ai = genai.GenerativeModel(AI_MODEL_NAME)
        client = Client()
        client.login(bs_handle, bs_pwd)
    except Exception as e:
        st.sidebar.error(f"Login/Init Error: {e}")

# --- Main Tabs ---
tab_growth, tab_manage, tab_engage, tab_research, tab_stats = st.tabs([
    "🚀 Growth", "👥 Followers", "💬 Engagement", "📈 Analysis", "📊 Stats"
])

if not client:
    st.warning("サイドバーで接続設定を完了してください。")
else:
    # --- TAB 1: Growth ---
    with tab_growth:
        col1, col2 = st.columns(2)
        with col1:
            st.subheader("🧹 片思い解除")
            unfol_limit = st.number_input("Check limit", 10, 2000, 300, key="unfol_limit")
            if st.button("💔 実行する"):
                st.info("データ取得中...")
                following = get_all_follows(client, client.me.did, max_count=unfol_limit)
                followers_dids = [f.did for f in get_all_followers(client, client.me.did, max_count=unfol_limit*2)]

                log_placeholder = st.empty()
                logs = []
                count = 0
                for f in following:
                    if f.did not in followers_dids:
                        try:
                            if f.viewer and f.viewer.following:
                                client.app.bsky.graph.follow.delete(client.me.did, f.viewer.following.split('/')[-1])
                                logs.append(f"⚠️ Unfollowed: @{f.handle}")
                                count += 1
                                log_placeholder.markdown(f'<div class="log-container">{"<br>".join(logs[-10:])}</div>', unsafe_allow_html=True)
                                time.sleep(1.0)
                        except Exception as e:
                            st.error(f"Unfollow Error (@{f.handle}): {e}")
                            continue
                st.success(f"完了: {count}名解除")

        with col2:
            st.subheader("➕ ターゲットフォロー")
            f_count = st.number_input("Follow count", 1, 100, 10, key="f_count")
            st.markdown('<p class="warning-text">⚠️ 凍結リスク注意</p>', unsafe_allow_html=True)
            do_like = st.checkbox("いいねもする", value=True)

            if st.button("⚡ 実行する"):
                total = 0
                log_placeholder = st.empty()
                logs = []
                for kw in target_kws:
                    if total >= f_count: break
                    st.write(f"🔍 Searching: {kw}")
                    try:
                        search = client.app.bsky.actor.search_actors({'term': kw, 'limit': 40})
                        for a in search.actors:
                            if total >= f_count: break
                            try:
                                client.follow(a.did)
                                logs.append(f"✅ Followed: @{a.handle}")
                                total += 1
                                if do_like:
                                    feed = client.app.bsky.feed.get_author_feed({'actor': a.did, 'limit': 1}).feed
                                    if feed: client.like(feed[0].post.uri, feed[0].post.cid)
                                log_placeholder.markdown(f'<div class="log-container">{"<br>".join(logs[-10:])}</div>', unsafe_allow_html=True)
                                time.sleep(1.5)
                            except: continue
                    except Exception as e:
                        st.error(f"Search Error: {e}")
                st.success("完了")

    # --- TAB 2: Follower Manager ---
    with tab_manage:
        st.subheader("👥 フォロワー分類")
        m_count = st.number_input("スキャン人数", 1, 200, 20)

        if st.button("分析・分類を開始"):
            followers = get_all_followers(client, client.me.did, max_count=m_count)
            data = []
            bar = st.progress(0)
            for i, f in enumerate(followers):
                try:
                    p = f"Bio: {f.description}. Keywords: {target_kws}. Categorize or 'Other'. Reply 'Category: [Name]'"
                    res = ai.generate_content(p)
                    cat = res.text.split(":")[-1].strip()
                    data.append({"handle": f.handle, "did": f.did, "category": cat, "bio": f.description, "rkey": f.viewer.following.split('/')[-1] if f.viewer and f.viewer.following else None})
                except Exception as e:
                    st.error(f"AI/Data Error (@{f.handle}): {e}")
                    continue
                bar.progress((i+1)/len(followers))
                time.sleep(0.5)
            st.session_state.categorized = data

        if "categorized" in st.session_state:
            cats = list(set([x['category'] for x in st.session_state.categorized]))
            sel_cat = st.selectbox("フィルター", ["All"] + cats)
            for item in st.session_state.categorized:
                if sel_cat == "All" or item['category'] == sel_cat:
                    with st.container(border=True):
                        c1, c2 = st.columns([4, 1])
                        c1.write(f"**@{item['handle']}** | `{item['category']}`")
                        c1.caption(item['bio'][:150] if item['bio'] else "No bio")
                        if c2.button("🚫 Unfollow", key=f"un_{item['did']}"):
                            if item['rkey']:
                                try:
                                    client.app.bsky.graph.follow.delete(client.me.did, item['rkey'])
                                    save_removed_user(item['did'], item['handle'], item['category'], item['bio'])
                                    st.toast(f"Removed @{item['handle']}")
                                except Exception as e:
                                    st.error(f"Unfollow Error: {e}")

    # --- TAB 3: Community Engage ---
    with tab_engage:
        st.subheader("💬 フォロワーと交流")
        e_num = st.number_input("交流人数", 1, 50, 5)
        if st.button("自動いいね＆コメント開始"):
            followers = get_all_followers(client, client.me.did, max_count=e_num)
            log_p = st.empty()
            logs = []
            for f in followers:
                try:
                    feed = client.app.bsky.feed.get_author_feed({'actor': f.did, 'limit': 1}).feed
                    if feed:
                        post = feed[0].post
                        client.like(post.uri, post.cid)
                        rep = ai.generate_content(f"Reply kindly: {post.record.text}").text
                        client.send_post(text=rep, reply_to=models.AppBskyFeedPost.ReplyRef(
                            parent=models.create_strong_ref(post), root=models.create_strong_ref(post)))
                        logs.append(f"💬 Interacted: @{f.handle}")
                        log_p.markdown(f'<div class="log-container">{"<br>".join(logs[-10:])}</div>', unsafe_allow_html=True)
                    time.sleep(2.0)
                except Exception as e:
                    st.error(f"Engage Error (@{f.handle}): {e}")
                    continue
            st.success("完了")

    # --- TAB 4: Analysis ---
    with tab_research:
        st.subheader("🔍 バズり分析 & 調査")
        r_kw = st.text_input("分析ワード", value="Python")
        c1, c2 = st.columns(2)
        with c1:
            if st.button("🚀 バイラル調査"):
                st.write("調査中...")
                try:
                    search = client.app.bsky.feed.search_posts({'q': r_kw, 'limit': 25})
                    found = 0
                    for p in search.posts:
                        try:
                            ap = client.get_profile(p.author.did)
                            # フォロワー2000人以下で、いいねが30以上の「効率よくバズっている」投稿を探す
                            if ap.followers_count < 2000 and (p.like_count or 0) > 30:
                                found += 1
                                with st.expander(f"🔥 @{ap.handle} ({p.like_count} Likes)"):
                                    st.write(p.record.text)
                                    analysis = ai.generate_content(f"Analyze why this post succeeded and provide a template based on it: {p.record.text}")
                                    st.info(analysis.text)
                        except Exception as inner_e:
                            st.warning(f"Post Analysis Error: {inner_e}")
                            continue
                    if found == 0:
                        st.write("条件に合う投稿が見つかりませんでした。")
                except Exception as e:
                    st.error(f"Viral Research Error: {e}")

        with c2:
            if st.button("🕵️ 関心事調査"):
                st.write("調査中...")
                try:
                    fols = get_all_followers(client, client.me.did, max_count=5)
                    txts = ""
                    for f in fols:
                        try:
                            lks = client.app.bsky.feed.get_actor_likes({'actor': f.did, 'limit': 3}).feed
                            for l in lks: txts += f"\n- {l.post.record.text}"
                        except: continue
                    if txts:
                        summary = ai.generate_content(f"Summarize trending topics from these posts and suggest a new post idea: {txts}")
                        st.markdown(summary.text)
                    else:
                        st.write("データが取得できませんでした。")
                except Exception as e:
                    st.error(f"Interest Research Error: {e}")

    # --- TAB 5: Stats ---
    with tab_stats:
        st.subheader("📊 統計")
        if st.button("計算する"):
            try:
                fols = get_all_followers(client, client.me.did, max_count=30)
                hit = 0
                for f in fols:
                    try:
                        res = ai.generate_content(f"Match {target_kws}? {f.description}")
                        if "YES" in res.text.upper(): hit += 1
                    except: continue
                if len(fols) > 0:
                    st.metric("ターゲット合致率", f"{(hit/len(fols))*100:.1f}%")
                else:
                    st.write("フォロワーが見つかりません。")
            except Exception as e:
                st.error(f"Stats Error: {e}")

