            for f in followers:
                try:
                    feed_res = client.app.bsky.feed.get_author_feed({'actor': f.did, 'limit': 1})
                    if feed_res.feed:
                        post = feed_res.feed[0].post
                        client.like(post.uri, post.cid)
                        rep = ai.generate_content(f"Reply kindly and shortly to this post: {post.record.text}").text
                        client.send_post(text=rep, reply_to=models.AppBskyFeedPost.ReplyRef(
                            parent=models.create_strong_ref(post), root=models.create_strong_ref(post)))
                        logs.append(f"💬 Interacted: @{f.handle}")
                        log_p.markdown(f'<div class="log-container">{"<br>".join(logs[-10:])}</div>', unsafe_allow_html=True)
                    time.sleep(2.0)
                except Exception as e:
                    continue
            st.success("完了")

    # --- TAB 4: Analysis ---
    with tab_research:
        st.subheader("🔍 バズり分析 & 調査")
        r_kw = st.text_input("分析キーワード (例: Python, AI開発)", value="Python")
        c1, c2 = st.columns(2)
        with c1:
            st.markdown("### 🚀 バイラル投稿調査")
            st.caption("フォロワーが少ないのにバズっている投稿を分析します")
            if st.button("調査開始"):
                with st.spinner("検索中..."):
                    try:
                        search = client.app.bsky.feed.search_posts({'q': r_kw, 'limit': 50})
                        found = 0
                        for p in search.posts:
                            try:
                                ap = client.get_profile(p.author.did)
                                # バズり条件: フォロワー5000以下かつ、いいね30以上
                                if ap.followers_count < 5000 and (p.like_count or 0) > 20:
                                    found += 1
                                    with st.expander(f"🔥 @{ap.handle} ({p.like_count} Likes)"):
                                        st.write(p.record.text)
                                        if ai:
                                            analysis = ai.generate_content(f"Analyze why this post is getting likes and provide a short reusable template: {p.record.text}")
                                            st.info(analysis.text)
                            except: continue
                        if found == 0: st.write("条件に合う投稿が見つかりませんでした。")
                    except Exception as e:
                        st.error(f"Search Error: {e}")

        with c2:
            st.markdown("### 🕵️ フォロワーの関心事")
            st.caption("フォロワーが最近「いいね」した投稿からトレンドを探ります")
            if st.button("トレンド分析"):
                with st.spinner("フォロワーの動向を分析中..."):
                    try:
                        fols = get_all_followers(client, client.me.did, max_count=10)
                        combined_text = ""
                        for f in fols:
                            try:
                                lks = client.app.bsky.feed.get_actor_likes({'actor': f.did, 'limit': 3})
                                for l in lks.feed:
                                    combined_text += f"\n- {l.post.record.text}"
                            except: continue
                        if combined_text and ai:
                            summary = ai.generate_content(f"Based on these posts my followers liked, what are the current hot topics? Suggest 3 post ideas: {combined_text}")
                            st.markdown(summary.text)
                        else:
                            st.write("分析に十分なデータが見つかりませんでした。")
                    except Exception as e:
                        st.error(f"Trend Analysis Error: {e}")

    # --- TAB 5: Stats ---
    with tab_stats:
        st.subheader("📊 統計")
        if st.button("ターゲット適合率を計算"):
            with st.spinner("計算中..."):
                try:
                    fols = get_all_followers(client, client.me.did, max_count=20)
                    hit = 0
                    for f in fols:
                        try:
                            res = ai.generate_content(f"Does this bio match any of these keywords: {target_kws}? Bio: {f.description}. Answer only YES or NO.")
                            if "YES" in res.text.upper(): hit += 1
                        except: continue
                    if fols:
                        st.metric("ターゲット適合率 (直近20名)", f"{(hit/len(fols))*100:.1f}%")
                    else:
                        st.write("フォロワーがいません")
                except Exception as e:
                    st.error(f"Stats Error: {e}")
